/* HumanGuard SDK v1.0.0 — https://github.com/rubenbetabdishoo/HumanGuard
 * Drop-in bot detection. No dependencies. MIT License.
 * Usage: <script src="humanGuard.min.js" data-api-key="hg_live_XXXX"></script>
 */
(function (w, d) {
  'use strict';

  /* ── Config from script tag ──────────────────────────────────────── */
  var el = d.currentScript || (function () {
    var tags = d.querySelectorAll('script[data-api-key]');
    return tags[tags.length - 1];
  })();

  var CFG = {
    apiKey:    el ? (el.getAttribute('data-api-key')    || '') : '',
    threshold: el ? parseFloat(el.getAttribute('data-threshold') || '0.5') : 0.5,
    autoScore: el ? (el.getAttribute('data-auto-score') !== 'false') : true,
    apiUrl:    el ? (el.getAttribute('data-api-url')    || 'https://9ixzk5e9u4.execute-api.us-east-1.amazonaws.com') : 'https://9ixzk5e9u4.execute-api.us-east-1.amazonaws.com',
    delay:     el ? parseInt(el.getAttribute('data-delay') || '30000', 10) : 30000,
  };

  /* ── Session identity ────────────────────────────────────────────── */
  var sessionId = 'hg-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 9);

  /* ── Privacy: honour Do Not Track ───────────────────────────────── */
  var dnt = (navigator.doNotTrack === '1' || w.doNotTrack === '1' || navigator.msDoNotTrack === '1');

  /* ── Signal buffers ──────────────────────────────────────────────── */
  var MAX_MOUSE  = 200;
  var buf = { mouseMoves: [], clicks: [], keys: [] };
  var lastMove   = 0;
  var sessionStart = Date.now();

  function _push(arr, max, item) { if (arr.length < max) arr.push(item); }

  if (!dnt) {
    d.addEventListener('mousemove', function (e) {
      var now = Date.now();
      if (now - lastMove < 100) return;
      lastMove = now;
      _push(buf.mouseMoves, MAX_MOUSE, { x: e.clientX, y: e.clientY, ts: now });
    });

    d.addEventListener('click', function (e) {
      _push(buf.clicks, 500, { x: e.clientX, y: e.clientY, button: e.button, ts: Date.now() });
    });

    /* Keystroke timing only — key content is intentionally omitted */
    d.addEventListener('keydown', function (e) {
      _push(buf.keys, 500, { code: e.code, ts: Date.now(), type: 'down' });
    });
    d.addEventListener('keyup', function (e) {
      _push(buf.keys, 500, { code: e.code, ts: Date.now(), type: 'up' });
    });
  }

  /* ── Scoring ─────────────────────────────────────────────────────── */
  var scored    = false;
  var result    = null;
  var callbacks = [];

  function _notify(res) {
    result = res;
    w.HumanGuard.result = res;
    try { d.dispatchEvent(new CustomEvent('humanGuard:scored', { detail: res, bubbles: false })); }
    catch (_) {}
    for (var i = 0; i < callbacks.length; i++) {
      try { callbacks[i](res); } catch (_) {}
    }
  }

  function _error(msg) {
    try { d.dispatchEvent(new CustomEvent('humanGuard:error', { detail: { error: msg }, bubbles: false })); }
    catch (_) {}
  }

  function score() {
    if (scored) return;
    scored = true;

    if (!CFG.apiKey) {
      _error('HumanGuard: data-api-key is required');
      return;
    }

    var payload = {
      sessionID: sessionId,
      metadata: {
        userAgent:      navigator.userAgent,
        viewportWidth:  w.innerWidth,
        viewportHeight: w.innerHeight,
        sessionDurationMs: Date.now() - sessionStart,
        dnt: dnt,
      },
      signals: {
        mouseMoves: buf.mouseMoves,
        clicks:     buf.clicks,
        keys:       buf.keys,
      },
    };

    var headers = { 'Content-Type': 'application/json', 'X-Api-Key': CFG.apiKey };
    if (dnt) headers['DNT'] = '1';

    fetch(CFG.apiUrl + '/api/score?explain=false', {
      method:  'POST',
      headers: headers,
      body:    JSON.stringify(payload),
    })
    .then(function (r) { return r.json(); })
    .then(function (data) {
      if (data.error) { _error(data.error); return; }
      _notify({
        prob_bot:   data.prob_bot,
        label:      data.label,
        threshold:  data.threshold,
        session_id: sessionId,
      });
    })
    .catch(function (err) { _error(err.message || 'Network error'); });
  }

  /* ── Auto-score after delay ──────────────────────────────────────── */
  var _timer = null;
  if (CFG.autoScore) {
    _timer = setTimeout(score, CFG.delay);
  }

  /* ── Score on form submit (capture phase so it fires first) ──────── */
  d.addEventListener('submit', function () {
    if (_timer) { clearTimeout(_timer); _timer = null; }
    score();
  }, true);

  /* ── Transparency comment ────────────────────────────────────────── */
  function _addComment() {
    var body = d.body;
    if (body) body.insertBefore(d.createComment(' HumanGuard active '), body.firstChild);
  }
  if (d.readyState === 'loading') {
    d.addEventListener('DOMContentLoaded', _addComment);
  } else {
    _addComment();
  }

  /* ── Public API ──────────────────────────────────────────────────── */
  w.HumanGuard = {
    /** Current session identifier */
    sessionId: sessionId,

    /** Last score result (null until scored) */
    result: null,

    /** Returns the current score object, or null if not yet scored */
    getScore: function () { return result; },

    /**
     * Register a callback invoked when scoring completes.
     * If already scored, callback fires immediately with the cached result.
     * @param {function} cb  Called with {prob_bot, label, threshold, session_id}
     */
    onScore: function (cb) {
      if (typeof cb !== 'function') return;
      callbacks.push(cb);
      if (result) { try { cb(result); } catch (_) {} }
    },

    /**
     * Trigger scoring immediately (ignores auto-score timer).
     * Safe to call multiple times — only scores once.
     */
    score: score,
  };

}(window, document));
